const COLOR = 'red';
function drawPoint(ctx, y, x, r) {
ctx.beginPath();
ctx.arc(x, y, r, 0, 2 * Math.PI);
ctx.fillStyle = COLOR;
ctx.fill();
}
```

```py
function drawSegment([ay, ax], [by, bx], scale, ctx) {
ctx.beginPath();
ctx.moveTo(ax * scale, ay * scale);
ctx.lineTo(bx * scale, by * scale);
ctx.lineWidth = '10px';
ctx.strokeStyle = COLOR;
ctx.stroke();
}
```

